            value={(profileData[section] as any)[field] || ''} 
            onChange={(e) => handleInputChange(section, field, e.target.value)}
            className="w-full px-4 py-2.5 rounded-xl bg-gray-50 border border-gray-200 focus:border-luGreen focus:outline-none text-sm"
            placeholder={placeholder}
          />
      </div>
  );

  const renderRating = (field: string, label: string) => (
      <div className="flex items-center justify-between p-3 bg-gray-50 rounded-xl">
          <span className="text-sm font-bold text-gray-700">{label}</span>
          <div className="flex gap-1">
              {[1, 2, 3, 4, 5].map((star) => (
                  <button 
                    key={star} 
